// ═══════════════════════════════════════════════════════════════════════
// Handler
// ═══════════════════════════════════════════════════════════════════════

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  var user = await getAuthenticatedUser(req);
  if (!user || user.email !== ADMIN_EMAIL) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  // Optional: ?slug=mac-brazel-roswell-debris-discovery-1947 to update just one
  var targetSlug = req.query.slug as string | undefined;

  var supabase = createClient(supabaseUrl, supabaseServiceKey);
  var results = { updated: 0, skipped: 0, errors: [] as string[], details: [] as Array<{slug: string; oldLen: number; newLen: number}> };

  var entries = ENRICHED_DESCRIPTIONS;
  if (targetSlug) {
    entries = entries.filter(function(e) { return e.slug === targetSlug; });
    if (entries.length === 0) {
      return res.status(400).json({ error: 'Slug not found in enrichment list: ' + targetSlug });
    }
  }

  for (var i = 0; i < entries.length; i++) {
    var entry = entries[i];

    // Fetch current description
    var { data: report, error: fetchErr } = await supabase
      .from('reports')
      .select('id, description')
      .eq('slug', entry.slug)
      .single();

    if (fetchErr || !report) {
      results.errors.push('Not found: ' + entry.slug);
      results.skipped++;
      continue;
    }

    var oldLen = (report.description || '').length;
    var newLen = entry.description.length;

    // Safety: don't replace with shorter content unless it's marginal
    if (newLen < oldLen * 0.8) {
      results.errors.push('New description shorter than 80% of old for ' + entry.slug + ' (old=' + oldLen + ', new=' + newLen + '). Skipping.');
      results.skipped++;
      continue;
    }

    var { error: updateErr } = await supabase
      .from('reports')
      .update({ description: entry.description })
      .eq('id', report.id);

    if (updateErr) {
      results.errors.push('Update failed for ' + entry.slug + ': ' + updateErr.message);
    } else {
      results.updated++;
      results.details.push({ slug: entry.slug, oldLen: oldLen, newLen: newLen });
    }
  }

  // Invalidate AI insights for updated reports
  if (results.updated > 0) {
    var updatedSlugs = results.details.map(function(d) { return d.slug; });
    var { data: updatedReports } = await supabase
      .from('reports')
      .select('id')
      .in('slug', updatedSlugs);

    if (updatedReports && updatedReports.length > 0) {
      var ids = updatedReports.map(function(r: any) { return r.id; });
      await supabase.from('report_insights')
        .update({ is_stale: true })
        .in('report_id', ids);
    }
  }

  return res.status(200).json({
    success: true,
    results: results,
    message: 'Updated ' + results.updated + ' of ' + entries.length + ' descriptions',
  });
}
